import { useState, useMemo } from "react";
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  AreaChart, Area, CartesianGrid,
} from "recharts";
import { Search, Skull, TrendingUp, TrendingDown, Globe, AlertTriangle, Filter } from "lucide-react";
import { CONFLICTS, getDailyDeaths, getDateString, getRegionData, getTrendData } from "./data/conflicts";
import ConflictCard from "./components/ConflictCard";

const SEVERITY_FILTERS = ["all", "major_war", "war", "conflict"] as const;
const TREND_FILTERS = ["all", "escalating", "stable", "de-escalating"] as const;

const severityLabels: Record<string, string> = {
  all: "All",
  major_war: "Major War",
  war: "War",
  conflict: "Conflict",
};

const CustomTooltip = ({ active, payload, label }: any) => {
  if (!active || !payload?.length) return null;
  return (
    <div className="bg-zinc-900 border border-zinc-700 px-2 py-1.5 text-[10px]">
      <p className="text-zinc-300 font-medium mb-0.5">{label}</p>
      {payload.map((p: any, i: number) => (
        <p key={i} style={{ color: p.color }}>
          {p.name}: {typeof p.value === "number" ? p.value.toLocaleString() : p.value}
        </p>
      ))}
    </div>
  );
};

export default function App() {
  const [search, setSearch] = useState("");
  const [severityFilter, setSeverityFilter] = useState<typeof SEVERITY_FILTERS[number]>("all");
  const [trendFilter, setTrendFilter] = useState<typeof TREND_FILTERS[number]>("all");
  const [showCharts, setShowCharts] = useState(true);

  const today = getDateString(0);

  // Compute today's deaths for each conflict and sort
  const conflictsWithDeaths = useMemo(() => {
    return CONFLICTS.map(c => ({
      ...c,
      todayDeaths: getDailyDeaths(c, today),
    })).sort((a, b) => b.todayDeaths - a.todayDeaths);
  }, [today]);

  // Summary stats
  const totalToday = useMemo(() => conflictsWithDeaths.reduce((s, c) => s + c.todayDeaths, 0), [conflictsWithDeaths]);
  const escalatingCount = CONFLICTS.filter(c => c.trend === "escalating").length;
  const activeCount = CONFLICTS.length;

  // Charts data
  const trendData = useMemo(() => getTrendData(CONFLICTS, 14), []);
  const regionData = useMemo(() => getRegionData(CONFLICTS, today), [today]);

  // Filtered conflicts
  const filtered = useMemo(() => {
    return conflictsWithDeaths.filter(c => {
      if (search) {
        const q = search.toLowerCase();
        const match = c.name.toLowerCase().includes(q) ||
          c.country.toLowerCase().includes(q) ||
          c.region.toLowerCase().includes(q) ||
          c.parties.some(p => p.toLowerCase().includes(q));
        if (!match) return false;
      }
      if (severityFilter !== "all" && c.severity !== severityFilter) return false;
      if (trendFilter !== "all" && c.trend !== trendFilter) return false;
      return true;
    });
  }, [conflictsWithDeaths, search, severityFilter, trendFilter]);

  const regionChartHeight = Math.max(160, regionData.length * 30);

  return (
    <div className="w-full h-full overflow-auto bg-zinc-950 text-zinc-100">
      {/* Summary Bar */}
      <div className="sticky top-0 z-10 bg-zinc-950 border-b border-zinc-800">
        <div className="grid grid-cols-3 gap-0 divide-x divide-zinc-800">
          <div className="px-4 py-3 flex items-center gap-3">
            <Skull className="w-5 h-5 text-red-400 shrink-0" />
            <div>
              <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Est. Deaths Today</div>
              <div className="text-xl font-bold text-red-400">{totalToday.toLocaleString()}</div>
            </div>
          </div>
          <div className="px-4 py-3 flex items-center gap-3">
            <Globe className="w-5 h-5 text-blue-400 shrink-0" />
            <div>
              <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Active Zones</div>
              <div className="text-xl font-bold text-blue-400">{activeCount}</div>
            </div>
          </div>
          <div className="px-4 py-3 flex items-center gap-3">
            <AlertTriangle className="w-5 h-5 text-orange-400 shrink-0" />
            <div>
              <div className="text-[10px] text-zinc-500 uppercase tracking-wider">Escalating</div>
              <div className="text-xl font-bold text-orange-400">{escalatingCount}</div>
            </div>
          </div>
        </div>
        <div className="px-3 py-1 text-[9px] text-zinc-600 border-t border-zinc-800/50">
          {today} Ã‚Â· Estimates based on ACLED, UCDP & ICG conflict data methodologies Ã‚Â· Daily variation is model-generated
        </div>
      </div>

      {/* Charts Toggle */}
      <div className="px-3 pt-3 pb-1">
        <button
          onClick={() => setShowCharts(!showCharts)}
          className="text-[10px] text-zinc-500 hover:text-zinc-300 flex items-center gap-1 transition-colors"
        >
          <TrendingUp className="w-3 h-3" />
          {showCharts ? "Hide Charts" : "Show Charts"}
        </button>
      </div>

