import { useState } from "react";
import { ChevronDown, ChevronUp, Skull, Users, Calendar } from "lucide-react";
import { Conflict, getDailyDeaths, getDateString } from "../data/conflicts";

const severityColors = {
  major_war: { bg: "bg-red-500/15", text: "text-red-400", border: "border-red-500/30", label: "Major War" },
  war: { bg: "bg-orange-500/15", text: "text-orange-400", border: "border-orange-500/30", label: "War" },
  conflict: { bg: "bg-yellow-500/15", text: "text-yellow-400", border: "border-yellow-500/30", label: "Conflict" },
};

const trendColors = {
  escalating: "text-red-400",
  stable: "text-zinc-400",
  "de-escalating": "text-green-400",
};

const trendIcons = {
  escalating: "↑",
  stable: "→",
  "de-escalating": "↓",
};

export default function ConflictCard({ conflict }: { conflict: Conflict }) {
  const [expanded, setExpanded] = useState(false);
  const today = getDateString(0);
  const todayDeaths = getDailyDeaths(conflict, today);
  const weekDeaths = Array.from({ length: 7 }, (_, i) => getDailyDeaths(conflict, getDateString(i))).reduce((a, b) => a + b, 0);
  const monthDeaths = Array.from({ length: 30 }, (_, i) => getDailyDeaths(conflict, getDateString(i))).reduce((a, b) => a + b, 0);
  const sev = severityColors[conflict.severity];

  // Mini sparkline data for last 7 days
  const sparkData = Array.from({ length: 7 }, (_, i) => getDailyDeaths(conflict, getDateString(6 - i)));
  const maxSpark = Math.max(...sparkData, 1);

  return (
    <div
      className={`border ${sev.border} ${sev.bg} transition-all cursor-pointer`}
      onClick={() => setExpanded(!expanded)}
    >
      <div className="px-3 py-2.5 flex items-center gap-3">
        {/* Left: rank indicator */}
        <div className="flex flex-col items-center gap-0.5 shrink-0 w-12">
          <Skull className={`w-3.5 h-3.5 ${sev.text}`} />
          <span className={`text-lg font-bold ${sev.text} leading-none`}>{todayDeaths}</span>
          <span className="text-[9px] text-zinc-500">today</span>
        </div>

        {/* Middle: info */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="text-sm font-semibold text-zinc-100 truncate">{conflict.name}</span>
            <span className={`text-[9px] px-1.5 py-0.5 font-medium ${sev.bg} ${sev.text} border ${sev.border}`}>
              {sev.label}
            </span>
            <span className={`text-[9px] font-medium ${trendColors[conflict.trend]}`}>
              {trendIcons[conflict.trend]} {conflict.trend}
            </span>
          </div>
          <div className="text-[10px] text-zinc-500 mt-0.5">
            {conflict.country} · {conflict.parties.join(" vs ")}
          </div>
        </div>

        {/* Sparkline */}
        <div className="shrink-0 flex items-end gap-px h-5">
          {sparkData.map((v, i) => (
            <div
              key={i}
              className={`w-1 ${sev.text} opacity-60`}
              style={{
                height: `${Math.max(2, (v / maxSpark) * 20)}px`,
                backgroundColor: "currentColor",
              }}
            />
          ))}
        </div>

        {/* Expand icon */}
        <div className="shrink-0">
          {expanded ? (
            <ChevronUp className="w-4 h-4 text-zinc-500" />
          ) : (
            <ChevronDown className="w-4 h-4 text-zinc-500" />
          )}
        </div>
      </div>

      {expanded && (
        <div className="px-3 pb-3 border-t border-zinc-800/50 pt-2 space-y-2">
          <p className="text-[11px] text-zinc-400 leading-relaxed">{conflict.description}</p>
          <div className="grid grid-cols-4 gap-2">
            <div className="bg-zinc-900/60 px-2 py-1.5">
              <div className="text-[9px] text-zinc-500 flex items-center gap-1">
                <Skull className="w-2.5 h-2.5" /> Today
              </div>
              <div className={`text-sm font-bold ${sev.text}`}>{todayDeaths}</div>
            </div>
            <div className="bg-zinc-900/60 px-2 py-1.5">
              <div className="text-[9px] text-zinc-500 flex items-center gap-1">
                <Calendar className="w-2.5 h-2.5" /> 7 Days
              </div>
              <div className="text-sm font-bold text-zinc-200">{weekDeaths.toLocaleString()}</div>
            </div>
            <div className="bg-zinc-900/60 px-2 py-1.5">
              <div className="text-[9px] text-zinc-500 flex items-center gap-1">
                <Calendar className="w-2.5 h-2.5" /> 30 Days
              </div>
              <div className="text-sm font-bold text-zinc-200">{monthDeaths.toLocaleString()}</div>
            </div>
            <div className="bg-zinc-900/60 px-2 py-1.5">
              <div className="text-[9px] text-zinc-500 flex items-center gap-1">
                <Users className="w-2.5 h-2.5" /> Total
              </div>
              <div className="text-sm font-bold text-zinc-300">{conflict.cumulativeDeaths.toLocaleString()}+</div>
            </div>
          </div>
          <div className="text-[9px] text-zinc-600">
            Since {conflict.startYear} · Parties: {conflict.parties.join(", ")}
          </div>
        </div>
      )}
    </div>
  );
}
